form:Form.form:Scripts:
		
function set_banco_hs()
{	
	if(Ctrl("main").GetMode() == 'LIST')
	{
		Ctrl('oi_banco_hs').SetXValue(Ctrl('LIST').GetSelectAttrValue("oi_banco_hora_l"));		
	}
	else
	{
		Ctrl('oi_banco_hs').SetXValue(Ctrl('oi_banco_hora').GetXValue());		
	}	
	Ctrl('COMP_FC').DoEvent("CALL:COMP_FC");
}

//En modo NEW - Puede seleccionarse
function unidad_banco()
{ 	
	var Param=new NomadXML("PARAM");
	Param.SetAttr("oi_banco_hora", Ctrl('oi_banco_hora').GetXValue());

	var Data =new NomadXML();
	Data = GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_UNIDAD"), Param.ToString())	

	Ctrl('c_unidad_tiempo').SetXValue(Data.GetAttr("c_unidad_tiempo").toString()); 	

	//Limpiar controles 		
	Ctrl('t_cant_gen').SetXValue("");
	Ctrl('t_cant_aprob').SetXValue("");  
	if(Ctrl('t_cant_aprob_ant') != undefined)
	{
		Ctrl('t_cant_aprob_ant').SetXValue("");	
	}

	Ctrl('t_consumidos').SetXValue("");
	Ctrl('t_saldo').SetXValue("");

	if(Ctrl('oi_banco_hora').GetXValue() != "")
	{
		//Habilitar controles	                              
		Ctrl('t_cant_gen').SetEnabled(true);
		Ctrl('t_cant_aprob').SetEnabled(true);
		if(Ctrl('t_cant_aprob_ant') != undefined)
		{
			Ctrl('t_cant_aprob_ant').SetEnabled(true);
		}
		Ctrl('t_consumidos').SetEnabled(true);
		Ctrl('t_saldo').SetEnabled(true);
	} 
	else		
	{
		//Habilitar controles	                              
		Ctrl('t_cant_gen').SetEnabled(false);
		Ctrl('t_cant_aprob').SetEnabled(false);
		if(Ctrl('t_cant_aprob_ant') != undefined)
		{
			Ctrl('t_cant_aprob_ant').SetEnabled(false);
		}
		Ctrl('t_consumidos').SetEnabled(false);
		Ctrl('t_saldo').SetEnabled(false);
	}                              

}



function formatear_hora(par1,par2)
{
	if(par1.GetXValue() != '')
	{
		if (par1.GetXValue().toString().length == 1) 
		{							
			par2.SetXValue("0" + par1.GetXValue() + ":00");
		}
		else
		{
			par2.SetXValue(par1.GetXValue() + ":00");
		}		
	} 
} 

function formatear_minuto(par1,par2)
{
	var resultado = "";			
	var cantidad = parseInt(par1.GetXValue());

	var hora = Math.floor(cantidad / 60); 
	var minutos = cantidad - (Math.floor(cantidad / 60) * 60);			

	if(par1.GetXValue() != '')
	{
		if (hora.toString().length == 1) 
		{			
			resultado = "0" + hora.toString();			
		}
		else
		{
			resultado = hora.toString();
		}	

		if (minutos.toString().length == 1) 
		{
			resultado = resultado + ":0" + minutos.toString();
		}
		else
		{
			resultado = resultado + ":" + minutos.toString();
		}

		par2.SetXValue(resultado);									
	}    
}


function LoadForm()
{    
	if(Ctrl("main").GetMode() == "NEW") 
	{
		//Debe ingresar primero el banco de horas
		Ctrl('t_cant_gen').SetEnabled(false);
		Ctrl('t_cant_aprob').SetEnabled(false);   
		if(Ctrl('t_cant_aprob_ant') != undefined)
		{
			Ctrl('t_cant_aprob_ant').SetEnabled(false);
		}
		Ctrl('t_consumidos').SetEnabled(false);
		Ctrl('t_saldo').SetEnabled(false);			
		Ctrl('COMP_FC').SetEnabled(false);
	}

	if(Ctrl("main").GetMode() == "NEW" || Ctrl("main").GetMode() == "SHOW" || Ctrl("main").GetMode() == "EDIT")
	{
		var Param=new NomadXML("PARAM");
		Param.SetAttr("oi_banco_hora", Ctrl('oi_banco_hora').GetXValue());

		var Data =new NomadXML();
		Data = GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_UNIDAD"), Param.ToString())	

		Ctrl('c_unidad_tiempo').SetXValue(Data.GetAttr("c_unidad_tiempo").toString());					

		if (Data.GetAttr("c_unidad_tiempo").toString() == "" || Data.GetAttr("c_unidad_tiempo").toString() == "H") 
		{  	
			formatear_hora(Ctrl('n_cant_gen'),Ctrl('t_cant_gen'));
			formatear_hora(Ctrl('n_cant_aprob'),Ctrl('t_cant_aprob'));
			if(Ctrl('t_cant_aprob_ant') != undefined)
			{
				formatear_hora(Ctrl('n_cant_aprob_ant'),Ctrl('t_cant_aprob_ant'));
			}
			formatear_hora(Ctrl('n_consumidos'),Ctrl('t_consumidos'));
			formatear_hora(Ctrl('n_saldo'),Ctrl('t_saldo'));								
		} 


		if (Data.GetAttr("c_unidad_tiempo").toString() == "M")
		{     
			formatear_minuto(Ctrl('n_cant_gen'),Ctrl('t_cant_gen'));
			formatear_minuto(Ctrl('n_cant_aprob'),Ctrl('t_cant_aprob'));
			if(Ctrl('t_cant_aprob_ant') != undefined)
			{
				formatear_minuto(Ctrl('n_cant_aprob_ant'),Ctrl('t_cant_aprob_ant'));
			}
			formatear_minuto(Ctrl('n_consumidos'),Ctrl('t_consumidos'));
			formatear_minuto(Ctrl('n_saldo'),Ctrl('t_saldo'));			
		}  
	}
}                                 

function Validar(obj)
{	
	if(obj.GetXValue() !='')
	{                                                 
		var regexp = new RegExp("^([0-9]{1,3}|[0-9]{1,3}:[0-5][0-9])$");				      		                    
		if(!regexp.test(obj.GetXValue().toString()))
		{		
			obj.SetXValue("");
			alert("Formato correcto HHH:MM");
		}

		else
		{	

			if(obj.GetXValue().toString().indexOf(":") == -1) 
			{
				if (obj.GetXValue().toString().length == 1) 
				{							
					obj.SetXValue("0" + obj.GetXValue() + ":00");
				}
				else
				{
					obj.SetXValue(obj.GetXValue() + ":00");
				}
			}

			else
			{    				
				//Horas --> minutos :00
				if(Ctrl('c_unidad_tiempo').GetXValue() == "H" || Ctrl('c_unidad_tiempo').GetXValue() == "")
				{												
					if((obj.GetXValue().split(':')[1]).toString() != "00")
					{
						obj.SetXValue((obj.GetXValue().split(':')[0]).toString() + ":00");
					}
				}				
			}  
		}
	}
}				



function Convertir_Horas(par1,par2)  
{
	if(par1.GetXValue() !='')
	{
		par2.SetXValue(par1.GetXValue().split(':')[0]);
	}
	else
	{
		par2.SetXValue("");
	}
}

function Convertir_Minutos(par1,par2)
{
	if(par1.GetXValue() !='')
	{			
		par2.SetXValue(((parseInt(par1.GetXValue().split(':')[0]) * 60 ) + parseInt(par1.GetXValue().split(':')[1])).toString());									
	}	
	else
	{
		par2.SetXValue("");
	}
}

function ConvertirACantidad()
{	
	if(Ctrl('c_unidad_tiempo').GetXValue() == "H" || Ctrl('c_unidad_tiempo').GetXValue() == "")
	{		
		Convertir_Horas(Ctrl('t_cant_gen'),Ctrl('n_cant_gen'));
		Convertir_Horas(Ctrl('t_cant_aprob'),Ctrl('n_cant_aprob'));
		if(Ctrl('t_cant_aprob_ant') != undefined)
		{
			Convertir_Horas(Ctrl('t_cant_aprob_ant'),Ctrl('n_cant_aprob_ant'));
		}
		Convertir_Horas(Ctrl('t_consumidos'),Ctrl('n_consumidos'));
		Convertir_Horas(Ctrl('t_saldo'),Ctrl('n_saldo'));		
		return true;
	}  

	if(Ctrl('c_unidad_tiempo').GetXValue() == "M")
	{ 		      		
		Convertir_Minutos(Ctrl('t_cant_gen'),Ctrl('n_cant_gen'));
		Convertir_Minutos(Ctrl('t_cant_aprob'),Ctrl('n_cant_aprob'));
		if(Ctrl('t_cant_aprob_ant') != undefined)
		{
			Convertir_Minutos(Ctrl('t_cant_aprob_ant'),Ctrl('n_cant_aprob_ant'));
		}
		Convertir_Minutos(Ctrl('t_consumidos'),Ctrl('n_consumidos'));
		Convertir_Minutos(Ctrl('t_saldo'),Ctrl('n_saldo'));
		return true;
	}
}
